# --- WORKAROUND FÜR DJANGO 6.0 ---
# Da DOT nicht mehr importiert werden kann, definieren wir es hier manuell.
# Es wird im Paginator als Platzhalter für die Auslassungspunkte (...) genutzt.
DOT = "." 
