@register.simple_tag
def get_jazzmin_settings(request: WSGIRequest) -> Dict:
    settings_data = get_settings()

    admin_site = {x.name: x for x in all_sites}.get("admin", {})
    if not settings_data["site_title"]:
        settings_data["site_title"] = getattr(admin_site, "site_title", None)

    if not settings_data["site_header"]:
        settings_data["site_header"] = getattr(admin_site, "site_header", None)

    if not settings_data["site_brand"]:
        settings_data["site_brand"] = getattr(admin_site, "site_header", None)

    return settings_data


