@register.simple_tag
def get_user_avatar(user: AbstractUser) -> str:
    no_avatar = static("vendor/adminlte/img/user2-160x160.jpg")
    options = get_settings()
    avatar_field_name: Optional[Union[str, Callable]] = options.get("user_avatar")

    if not avatar_field_name:
        return no_avatar

    if callable(avatar_field_name):
        return avatar_field_name(user)

    avatar_field = getattr(user, avatar_field_name, None)
    if avatar_field is not None:
        if not avatar_field:
            return no_avatar
        if isinstance(avatar_field, str):
            return avatar_field
        elif hasattr(avatar_field, "url"):
            return avatar_field.url
        elif callable(avatar_field):
            return avatar_field()

    return no_avatar


@register.simple_tag
def jazzmin_paginator_number(cl, i):
    """
    Generate an individual page index link in a paginated list.
    Spezial-Fix für Django 6.0: Erzwingt Integer-Konvertierung für Berechnungen.
    """
    from django.contrib.admin.views.main import PAGE_VAR

    # 1. Sonderfall: Auslassungspunkte (...)
    if i == DOT:
        return mark_safe('<li class="page-item disabled"><a href="#" class="page-link">...</a></li>')

    # 2. i sicher in eine Ganzzahl (int) umwandeln
    # Wir nennen die Variable 'page_idx', um Verwirrung mit dem Original 'i' zu vermeiden
    try:
        page_idx = int(i)
    except (ValueError, TypeError):
        page_idx = 0  # Fallback auf die erste Seite

    # 3. Anzeige-Nummer berechnen (Muss eine Zahl sein!)
    display_number = page_idx + 1

    # 4. HTML zusammenbauen
    if page_idx == cl.page_num:
        html = '<li class="page-item active"><a href="#" class="page-link">{}</a></li>'.format(display_number)
    else:
        # Hier wird page_idx für den Link und display_number für den Text genutzt
        html = '<li class="page-item"><a href="{}" class="page-link">{}</a></li>'.format(
            cl.get_query_string({PAGE_VAR: page_idx}), display_number
        )

    return mark_safe(html)


@register.simple_tag
def admin_extra_filters(cl: ChangeList) -> Dict:
    used_parameters = list(itertools.chain(*(s.used_parameters.keys() for s in cl.filter_specs)))
    return {k: v for k, v in cl.params.items() if k not in used_parameters}


@register.simple_tag
def jazzmin_list_filter(cl: ChangeList, spec: ListFilter) -> SafeText:
    tpl = get_template(spec.template)
    choices = list(spec.choices(cl))
    field_key = get_filter_id(spec)

    for choice in choices:
        qs = choice.get("query_string")
        if not qs:
            continue

        query_parts = urllib.parse.parse_qs(qs[1:])
        for key in query_parts.keys():
            if key == field_key or key.startswith(field_key + "__") or "__" + field_key + "__" in key:
                choice["name"] = key
                choice["value"] = query_parts[key][0]

    return mark_safe(tpl.render({"field_name": field_key, "title": spec.title, "choices": choices, "spec": spec}))


