@register.simple_tag
def header_class(header: Dict, forloop: Dict) -> str:
    classes = []
    sorted_status, asc, desc = (
        header.get("sorted"),
        header.get("ascending"),
        header.get("descending"),
    )

    if forloop["counter0"] == 0 and header.get("class_attrib") == ' class="action-checkbox-column"':
        classes.append("djn-checkbox-select-all")

    if not header["sortable"]:
        return " ".join(classes)

    if sorted_status and asc:
        classes.append("sorting_asc")
    elif sorted_status and desc:
        classes.append("sorting_desc")
    else:
        classes.append("sorting")

    return " ".join(classes)


